function SliderCard({ src, label }: { src: string; label: string }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div
      className="relative rounded-[20px] overflow-hidden shrink-0 w-[320px] h-[220px] flex flex-col border border-white/10 cursor-pointer"
      style={{ background: "#0d0a1a", transform: hovered ? "scale(1.03) translateY(-4px)" : "scale(1) translateY(0)", transition: "transform 0.3s cubic-bezier(0.34,1.56,0.64,1)" }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <div className="flex-1 relative overflow-hidden">
        <img alt={label} className="absolute inset-0 w-full h-full object-cover" src={src} />
      </div>
      <div className="shrink-0 px-4 py-3">
        <p className="text-white text-[16px] font-['Inter:Medium',sans-serif] font-medium tracking-[-0.1px]">{label}</p>
      </div>
    </div>
  );
}

function MarqueeRow() {
  const cards = [
    { src: imgImage187, label: "Brand Identity" },
    { src: imgImage183, label: "Product Design" },
    { src: imgImage182, label: "Website Design" },
    { src: imgImage186, label: "Pitch Deck" },
    { src: imgImage192, label: "No-Code Development" },
    { src: imgImage181, label: "Motion Design" },
  ];
  const doubled = [...cards, ...cards];
  return (
    <div
      className="w-full overflow-hidden"
      style={{ maskImage: "linear-gradient(to right, transparent 0%, black 6%, black 94%, transparent 100%)" }}
    >
      <div
        className="flex gap-[24px] items-center w-max"
        style={{ animation: "marquee-ltr 40s linear infinite" }}
        onMouseEnter={e => (e.currentTarget.style.animationPlayState = "paused")}
        onMouseLeave={e => (e.currentTarget.style.animationPlayState = "running")}
      >
        {doubled.map((card, i) => (
          <SliderCard key={i} src={card.src} label={card.label} />
        ))}
      </div>
    </div>
  );
}

function Row() {
  return <MarqueeRow />;
}

